// Comprehensive webhook payload validation
const payload = inputs.webhook_payload || {};
const headers = inputs.webhook_headers || {};
const validationRules = inputs.validation_rules || {};

// Enhanced payload structure
const enhancedPayload = {
  original_payload: payload,
  metadata: {
    received_at: new Date().toISOString(),
    source_ip: headers['x-forwarded-for'] || headers['x-real-ip'] || 'unknown',
    user_agent: headers['user-agent'] || 'unknown',
    content_type: headers['content-type'] || 'unknown',
    webhook_id: generateWebhookId(),
    processing_status: 'pending'
  },
  validation_results: {
    is_valid: false,
    errors: [],
    warnings: []
  }
};

function generateWebhookId() {
  return `wh_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
}

// Payload validation logic
const validationErrors = [];
const validationWarnings = [];

// Required fields validation
if (validationRules.required_fields) {
  for (const field of validationRules.required_fields) {
    if (!payload.hasOwnProperty(field) || payload[field] === null || payload[field] === undefined) {
      validationErrors.push(`Missing required field: ${field}`);
    }
  }
}

// Data type validation
if (validationRules.field_types) {
  for (const [field, expectedType] of Object.entries(validationRules.field_types)) {
    if (payload.hasOwnProperty(field) && payload[field] !== null) {
      const actualType = Array.isArray(payload[field]) ? 'array' : typeof payload[field];
      if (actualType !== expectedType) {
        validationErrors.push(`Type mismatch for field ${field}: expected ${expectedType}, got ${actualType}`);
      }
    }
  }
}

// Custom validation rules
if (validationRules.custom_validations) {
  for (const validation of validationRules.custom_validations) {
    try {
      const result = evaluateCustomValidation(payload, validation);
      if (!result.passed) {
        if (validation.severity === 'error') {
          validationErrors.push(result.message);
        } else {
          validationWarnings.push(result.message);
        }
      }
    } catch (error) {
      validationErrors.push(`Custom validation error: ${error.message}`);
    }
  }
}

// Event source validation
if (validationRules.allowed_sources && headers['x-webhook-source']) {
  if (!validationRules.allowed_sources.includes(headers['x-webhook-source'])) {
    validationErrors.push(`Unauthorized webhook source: ${headers['x-webhook-source']}`);
  }
}

// Timestamp validation
if (payload.timestamp) {
  const eventTime = new Date(payload.timestamp);
  const now = new Date();
  const ageMinutes = (now - eventTime) / (1000 * 60);

  if (ageMinutes > 60) { // Event older than 1 hour
    validationWarnings.push(`Event is ${Math.round(ageMinutes)} minutes old`);
  }

  if (ageMinutes < -5) { // Event from future (clock skew tolerance)
    validationErrors.push(`Event timestamp is in the future: ${payload.timestamp}`);
  }
}

function evaluateCustomValidation(data, rule) {
  switch (rule.type) {
    case 'range_check':
      const value = data[rule.field];
      if (typeof value === 'number' && (value < rule.min || value > rule.max)) {
        return { passed: false, message: `${rule.field} value ${value} is outside range ${rule.min}-${rule.max}` };
      }
      break;

    case 'format_check':
      const stringValue = data[rule.field];
      if (typeof stringValue === 'string' && rule.pattern) {
        const regex = new RegExp(rule.pattern);
        if (!regex.test(stringValue)) {
          return { passed: false, message: `${rule.field} does not match required format` };
        }
      }
      break;

    case 'dependency_check':
      if (data[rule.primary_field] && !data[rule.dependent_field]) {
        return { passed: false, message: `${rule.dependent_field} is required when ${rule.primary_field} is present` };
      }
      break;

    case 'uniqueness_check':
      // This would typically check against a database or cache
      // For now, just validate the field exists
      if (!data[rule.field]) {
        return { passed: false, message: `Uniqueness field ${rule.field} is missing` };
      }
      break;
  }

  return { passed: true };
}

// Update validation results
enhancedPayload.validation_results.errors = validationErrors;
enhancedPayload.validation_results.warnings = validationWarnings;
enhancedPayload.validation_results.is_valid = validationErrors.length === 0;
enhancedPayload.metadata.processing_status = enhancedPayload.validation_results.is_valid ? 'validated' : 'invalid';

// Classify webhook event
if (enhancedPayload.validation_results.is_valid) {
  enhancedPayload.classification = classifyWebhookEvent(payload, headers);
}

function classifyWebhookEvent(payload, headers) {
  const classification = {
    event_type: 'unknown',
    priority: 'medium',
    category: 'general',
    processing_route: 'default'
  };

  // Event type detection
  if (payload.event || payload.event_type) {
    classification.event_type = payload.event || payload.event_type;
  } else if (payload.action) {
    classification.event_type = payload.action;
  }

  // Priority classification
  const highPriorityEvents = ['error', 'alert', 'critical', 'urgent', 'failure'];
  const lowPriorityEvents = ['info', 'debug', 'test', 'health_check'];

  if (highPriorityEvents.some(event => classification.event_type.toLowerCase().includes(event))) {
    classification.priority = 'high';
  } else if (lowPriorityEvents.some(event => classification.event_type.toLowerCase().includes(event))) {
    classification.priority = 'low';
  }

  // Category classification
  if (payload.user_id || payload.customer_id) {
    classification.category = 'user_event';
  } else if (payload.transaction_id || payload.payment_id) {
    classification.category = 'transaction_event';
  } else if (payload.system_id || payload.service_name) {
    classification.category = 'system_event';
  }

  // Processing route determination
  classification.processing_route = `${classification.category}_${classification.priority}`;

  return classification;
}

return {
  enhanced_payload: enhancedPayload,
  should_process: enhancedPayload.validation_results.is_valid,
  should_queue: !enhancedPayload.validation_results.is_valid && validationErrors.length < 3,
  should_reject: validationErrors.length >= 3
};

// High priority event processing with immediate actions
const enhancedPayload = inputs.enhanced_payload || {};
const payload = enhancedPayload.original_payload || {};
const classification = enhancedPayload.classification || {};

// Process high priority events with special handling
const processingResult = {
  webhook_id: enhancedPayload.metadata.webhook_id,
  processing_timestamp: new Date().toISOString(),
  priority_level: 'high',
  processing_actions: [],
  alerts_triggered: [],
  data_transformations: {}
};

// Immediate alert conditions
const alertConditions = [
  { field: 'error_count', operator: 'greater_than', value: 10, alert_type: 'error_spike' },
  { field: 'response_time', operator: 'greater_than', value: 5000, alert_type: 'performance_degradation' },
  { field: 'status', operator: 'equals', value: 'critical', alert_type: 'system_critical' }
];

for (const condition of alertConditions) {
  if (payload[condition.field] !== undefined) {
    const value = payload[condition.field];
    let shouldAlert = false;

    switch (condition.operator) {
      case 'greater_than':
        shouldAlert = value > condition.value;
        break;
      case 'less_than':
        shouldAlert = value < condition.value;
        break;
      case 'equals':
        shouldAlert = value === condition.value;
        break;
    }

    if (shouldAlert) {
      processingResult.alerts_triggered.push({
        alert_type: condition.alert_type,
        field: condition.field,
        value: value,
        threshold: condition.value,
        severity: 'high'
      });
    }
  }
}

// Real-time data transformations
processingResult.data_transformations = {
  normalized_timestamp: payload.timestamp ? new Date(payload.timestamp).toISOString() : new Date().toISOString(),
  event_id: payload.id || payload.event_id || enhancedPayload.metadata.webhook_id,
  source_system: payload.source || enhancedPayload.metadata.user_agent,
  processed_at: new Date().toISOString(),
  priority_score: calculatePriorityScore(payload, classification)
};

function calculatePriorityScore(data, classification) {
  let score = 50; // Base score

  // Adjust based on event type
  const criticalEvents = ['error', 'failure', 'critical', 'alert'];
  if (criticalEvents.some(event => classification.event_type.toLowerCase().includes(event))) {
    score += 30;
  }

  // Adjust based on data values
  if (data.error_count && data.error_count > 5) score += 20;
  if (data.severity === 'critical') score += 25;
  if (data.user_count && data.user_count > 1000) score += 15;

  return Math.min(100, score);
}

// Immediate processing actions
processingResult.processing_actions.push({
  action: 'cache_event',
  target: 'redis',
  key: `high_priority:${processingResult.webhook_id}`,
  ttl: 3600
});

processingResult.processing_actions.push({
  action: 'queue_for_analysis',
  target: 'kafka',
  topic: 'high-priority-events',
  partition_key: classification.category
});

if (processingResult.alerts_triggered.length > 0) {
  processingResult.processing_actions.push({
    action: 'trigger_notifications',
    channels: ['slack', 'pagerduty'],
    urgency: 'immediate'
  });
}

return {
  processing_result: processingResult,
  requires_immediate_action: processingResult.alerts_triggered.length > 0,
  cache_key: `high_priority:${processingResult.webhook_id}`,
  next_steps: processingResult.processing_actions
};

// Standard webhook event processing pipeline
const enhancedPayload = inputs.enhanced_payload || {};
const payload = enhancedPayload.original_payload || {};
const classification = enhancedPayload.classification || {};

const processingResult = {
  webhook_id: enhancedPayload.metadata.webhook_id,
  processing_timestamp: new Date().toISOString(),
  priority_level: classification.priority || 'medium',
  transformed_data: {},
  enrichments: {},
  quality_metrics: {}
};

// Standard data transformations
processingResult.transformed_data = {
  event_id: payload.id || payload.event_id || enhancedPayload.metadata.webhook_id,
  event_type: classification.event_type,
  event_category: classification.category,
  event_timestamp: payload.timestamp || enhancedPayload.metadata.received_at,
  source_ip: enhancedPayload.metadata.source_ip,
  user_agent: enhancedPayload.metadata.user_agent,
  raw_payload_size: JSON.stringify(payload).length,
  processing_latency_ms: Date.now() - new Date(enhancedPayload.metadata.received_at).getTime()
};

// Copy relevant payload fields
const relevantFields = ['user_id', 'session_id', 'transaction_id', 'amount', 'status', 'metadata'];
for (const field of relevantFields) {
  if (payload.hasOwnProperty(field)) {
    processingResult.transformed_data[field] = payload[field];
  }
}

// Data enrichment
processingResult.enrichments = {
  processing_route: classification.processing_route,
  geographical_info: extractGeographicalInfo(enhancedPayload.metadata.source_ip),
  device_info: parseUserAgent(enhancedPayload.metadata.user_agent),
  business_context: inferBusinessContext(payload)
};

function extractGeographicalInfo(ip) {
  // In a real implementation, this would use a GeoIP service
  return {
    ip_address: ip,
    country: 'Unknown',
    region: 'Unknown',
    city: 'Unknown'
  };
}

function parseUserAgent(userAgent) {
  // Simple user agent parsing
  return {
    raw_user_agent: userAgent,
    is_mobile: /Mobile|Android|iPhone/i.test(userAgent),
    is_bot: /bot|crawl|spider/i.test(userAgent),
    browser: extractBrowser(userAgent)
  };
}

function extractBrowser(userAgent) {
  if (/Chrome/i.test(userAgent)) return 'Chrome';
  if (/Firefox/i.test(userAgent)) return 'Firefox';
  if (/Safari/i.test(userAgent)) return 'Safari';
  if (/Edge/i.test(userAgent)) return 'Edge';
  return 'Unknown';
}

function inferBusinessContext(data) {
  const context = {
    business_unit: 'unknown',
    customer_segment: 'unknown',
    revenue_impact: 'none'
  };

  // Infer business context from data
  if (data.user_id) {
    context.business_unit = 'customer_operations';
    context.customer_segment = data.subscription_tier || 'standard';
  }

  if (data.transaction_id || data.amount) {
    context.business_unit = 'financial_operations';
    context.revenue_impact = data.amount > 100 ? 'high' : 'low';
  }

  return context;
}

// Data quality metrics
processingResult.quality_metrics = {
  completeness_score: calculateCompletenessScore(payload),
  timeliness_score: calculateTimelinessScore(payload.timestamp, enhancedPayload.metadata.received_at),
  validity_score: enhancedPayload.validation_results.is_valid ? 100 : 0,
  consistency_score: calculateConsistencyScore(payload)
};

function calculateCompletenessScore(data) {
  const expectedFields = ['id', 'timestamp', 'event_type', 'data'];
  const presentFields = expectedFields.filter(field => data.hasOwnProperty(field) && data[field] !== null);
  return Math.round((presentFields.length / expectedFields.length) * 100);
}

function calculateTimelinessScore(eventTimestamp, receivedAt) {
  if (!eventTimestamp) return 50; // Neutral score if no timestamp

  const eventTime = new Date(eventTimestamp);
  const receiveTime = new Date(receivedAt);
  const delayMinutes = (receiveTime - eventTime) / (1000 * 60);

  if (delayMinutes < 1) return 100;
  if (delayMinutes < 5) return 90;
  if (delayMinutes < 15) return 70;
  if (delayMinutes < 60) return 50;
  return 20;
}

function calculateConsistencyScore(data) {
  // Simple consistency checks
  let score = 100;

  // Check for data type consistency
  if (data.user_id && typeof data.user_id !== 'string') score -= 20;
  if (data.amount && typeof data.amount !== 'number') score -= 20;
  if (data.timestamp && isNaN(Date.parse(data.timestamp))) score -= 30;

  return Math.max(0, score);
}

return {
  processing_result: processingResult,
  storage_ready: true,
  quality_threshold_met: processingResult.quality_metrics.completeness_score >= 80
};

